const body = $input.first().json.body ?? $input.first().json;
const {
  patient_id, service_id, service_name, service_color,
  doctor_id, doctor_name, doctor_email, google_calendar_id,
  started_by, notes, first_appointment_id, steps
} = body;

if (!patient_id)           throw new Error('patient_id is required');
if (!service_id)           throw new Error('service_id is required');
if (!doctor_id)            throw new Error('doctor_id is required');
if (!first_appointment_id) throw new Error('first_appointment_id is required (appointment for step 1)');
if (!Array.isArray(steps) || steps.length === 0) throw new Error('steps array is required');

// Sort steps by step_number, ensure step 1 exists
const sortedSteps = [...steps].sort((a, b) => a.step_number - b.step_number);
if (sortedSteps[0].step_number !== 1) throw new Error('steps must include step_number 1');

// Compute date range for treatment_sequences
const calendarDates = sortedSteps
  .filter(s => s.schedule_mode === 'calendar' && s.scheduled_date)
  .map(s => s.scheduled_date)
  .sort();
const startedAt    = calendarDates[0] ?? new Date().toISOString().split('T')[0];
const expectedEnd  = calendarDates[calendarDates.length - 1] ?? null;

return [{ json: {
  patient_id,
  service_id,
  service_name,
  service_color: service_color ?? null,
  doctor_id,
  doctor_name:         doctor_name ?? null,
  doctor_email:        doctor_email ?? null,
  google_calendar_id:  google_calendar_id ?? null,
  started_by:          started_by ?? doctor_id,
  notes:               notes ?? null,
  first_appointment_id,
  steps:               sortedSteps,
  startedAt,
  expectedEnd,
} }];

