INSERT INTO treatment_sequences (
  patient_id, service_id, started_by, status, started_at, expected_end_at, notes
) VALUES (
  '{{ $json.patient_id }}',
  {{ $json.service_id }},
  '{{ $json.started_by }}',
  'active',
  '{{ $json.startedAt }}'::date,
  {{ $json.expectedEnd ? `'${$json.expectedEnd}'::date` : 'NULL' }},
  {{ $json.notes ? `'${$json.notes.replace(/'/g, "''")}'` : 'NULL' }}
)
RETURNING id;

