const sequenceId = $input.first().json.id;
const p = $('Parse Input').first().json;

// Build multi-row INSERT for ALL steps into treatment_seq_steps
const rows = p.steps.map(s => {
  const dateVal  = s.scheduled_date ? `'${s.scheduled_date}'::date` : 'NULL';
  const durVal   = s.duration_minutes ? parseInt(s.duration_minutes, 10) : 'NULL';
  const notesVal = s.notes ? `'${s.notes.replace(/'/g, "''")}'` : 'NULL';
  const nameVal  = `'${s.step_name.replace(/'/g, "''")}'`;
  return `(${sequenceId}, ${s.step_number}, ${nameVal}, ${dateVal}, ${durVal}, ${notesVal})`;
}).join(',\n  ');

const insertStepsSQL = `
  INSERT INTO treatment_seq_steps
    (sequence_id, step_position, step_name, scheduled_date, duration_minutes, notes)
  VALUES
    ${rows}
  RETURNING id, step_position
`;

return [{ json: { sequenceId, insertStepsSQL, parsed: p } }];

// Map step_position → treatment_seq_steps.id from the INSERT RETURNING rows
const insertedRows = $input.all();
const stepIdByPosition = {};
insertedRows.forEach(r => {
  if (r.json.id != null && r.json.step_position != null) {
    stepIdByPosition[r.json.step_position] = r.json.id;
  }
});

const p            = $('Parse Input').first().json;
const sequenceId   = $('Build Steps SQL').first().json.sequenceId;
const step1SeqId   = stepIdByPosition[1];

if (!step1SeqId) throw new Error('Could not find treatment_seq_steps.id for step 1');

// Link step 1 to the existing appointment (both sides of the FK)
const linkStep1SQL = `
  -- appointments gets the FK to the step
  UPDATE appointments
  SET treatment_seq_step_id = ${step1SeqId}, updated_at = NOW()
  WHERE id = '${p.first_appointment_id}';

  -- treatment_seq_steps gets the FK to the appointment + mark as waiting
  UPDATE treatment_seq_steps
  SET appointment_id   = '${p.first_appointment_id}',
      milestone_status = 'waiting',
      updated_at       = NOW()
  WHERE id = ${step1SeqId};
`;

// Calendar steps 2+ that have a scheduled_date → need new appointments
const laterCalendarSteps = p.steps.filter(
  s => s.step_number > 1 && s.schedule_mode === 'calendar' && s.scheduled_date
);

return [{ json: {
  sequenceId,
  stepIdByPosition,
  step1SeqId,
  linkStep1SQL,
  laterCalendarSteps,
  hasLaterSteps: laterCalendarSteps.length > 0,
  parsed: p,
} }];

const ctx          = $('Map Step IDs').first().json;
const p            = ctx.parsed;
const stepIdByPos  = ctx.stepIdByPosition;

// Build INSERT for each later calendar step
const rows = ctx.laterCalendarSteps.map(s => {
  const startTime  = `${s.scheduled_date}T09:00:00`;
  const durationMs = (s.duration_minutes ?? 60) * 60000;
  const endTime    = new Date(new Date(startTime).getTime() + durationMs)
                       .toISOString().replace('T', ' ').slice(0, 19);
  const startFmt   = startTime.replace('T', ' ');
  const notesVal   = s.notes ? `'${s.notes.replace(/'/g, "''")}'` : 'NULL';
  const summaryVal = `'Paso ${s.step_number}: ${s.step_name.replace(/'/g, "''")} '`;
  const calSrcId   = p.google_calendar_id
    ? `(SELECT id FROM calendar_sources WHERE google_calendar_id = '${p.google_calendar_id}' LIMIT 1)`
    : 'NULL';
  const seqStepId  = stepIdByPos[s.step_number];
  return {
    sql: `('${p.patient_id}', '${startFmt}'::timestamp, '${endTime}'::timestamp,
           '${p.doctor_id}', ${summaryVal}, ${notesVal}, 'scheduled',
           ${seqStepId}, ${calSrcId})`,
    step_number: s.step_number,
    seqStepId,
  };
});

const valueRows = rows.map(r => r.sql).join(',\n  ');

const insertSQL = `
  WITH inserted AS (
    INSERT INTO appointments
      (patient_id, start_datetime, end_datetime, assignee_id, summary, notes,
       status, treatment_seq_step_id, calendar_source_id)
    VALUES
      ${valueRows}
    RETURNING id, treatment_seq_step_id
  )
  UPDATE treatment_seq_steps s
  SET appointment_id   = i.id,
      milestone_status = 'waiting',
      updated_at       = NOW()
  FROM inserted i
  WHERE s.id = i.treatment_seq_step_id
  RETURNING s.id, s.step_position, i.id::text AS appointment_id
`;

return [{ json: { insertSQL, stepMeta: rows } }];

const rows = $input.all().filter(r => r.json.id);
const ctx  = $('Map Step IDs').first().json;
const p    = ctx.parsed;

const steps = rows.map(r => ({
  id:             r.json.id,
  step_number:    r.json.step_number,
  step_name:      r.json.step_name,
  scheduled_date: r.json.scheduled_date || null,
  appointment_id: r.json.appointment_id || null,
  is_lab_pending: !!r.json.is_lab_pending,
  status:         r.json.milestone_status === 'done'    ? 'completed'
                : r.json.milestone_status === 'waiting' ? 'scheduled'
                : r.json.milestone_status === 'alert'   ? 'missed'
                : 'pending',
  notes:          r.json.notes || null,
  duration_minutes: r.json.duration_minutes || null,
  completed_at:   r.json.completed_at || null,
}));

return [{ json: {
  sequence_id:    ctx.sequenceId,
  status:         'active',
  service_name:   p.service_name,
  service_color:  p.service_color,
  started_at:     p.startedAt,
  doctor_id:      p.doctor_id,
  doctor_name:    p.doctor_name,
  steps,
} }];
